def categorize_e_number(e_number: str) -> str:
    try:
        num = int(e_number[1:])  # Extract the numeric part
    except ValueError:
        return "Invalid E number format"

    if 100 <= num <= 199:
        return "Color"
    elif 200 <= num <= 299:
        return "Preservative"
    elif 300 <= num <= 399:
        return "Antioxidant or acidity regulator"
    elif 400 <= num <= 499:
        return "Thickener, stabilizer, or emulsifier"
    elif 500 <= num <= 599:
        return "pH regulator"
    elif 600 <= num <= 699:
        return "Flavor enhancer"
    elif 700 <= num <= 799:
        return "Antibiotic"
    elif 900 <= num <= 999:
        return "Glazing agent, gas, or sweetener"
    else:
        return "Unknown category"

# Example usage:
print(categorize_e_number("E120"))  # Output: Color
